import React, { useState } from 'react';
import { Plus } from 'lucide-react';

const TodoForm = ({ addTodo }) => {
  const [task, setTask] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (task.trim()) {
      addTodo(task.trim());
      setTask('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="flex items-center gap-2 w-full max-w-lg mx-auto mb-8">
      <label htmlFor="todo-input" className="sr-only">
        Add a new todo task
      </label>
      <input
        type="text"
        id="todo-input"
        className="flex-grow p-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-primary-500 focus:border-transparent outline-none transition-all duration-200 shadow-sm text-gray-800 placeholder-gray-400"
        placeholder="What needs to be done?"
        value={task}
        onChange={(e) => setTask(e.target.value)}
        aria-label="New todo task"
      />
      <button
        type="submit"
        className="flex-shrink-0 bg-primary-500 text-white p-3 rounded-lg shadow-md hover:bg-primary-600 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:ring-offset-2 transition-all duration-200 flex items-center justify-center gap-1"
        aria-label="Add todo"
      >
        <Plus size={20} />
        <span className="hidden sm:inline">Add Task</span>
      </button>
    </form>
  );
};

export default TodoForm;

