import React, { useState, useEffect, useCallback, useMemo } from 'react';
import TodoForm from './TodoForm';
import TodoItem from './TodoItem';
import useTodos from '../hooks/useTodos';
import { ListTodo, Search, XCircle } from 'lucide-react';

const TodoList = () => {
  const { todos, addTodo, toggleComplete, deleteTodo, editTodo } = useTodos();
  const [filter, setFilter] = useState('all'); // 'all', 'active', 'completed'
  const [searchTerm, setSearchTerm] = useState('');

  const filteredTodos = useMemo(() => {
    let filtered = todos;

    if (filter === 'active') {
      filtered = filtered.filter(todo => !todo.completed);
    } else if (filter === 'completed') {
      filtered = filtered.filter(todo => todo.completed);
    }

    if (searchTerm) {
      filtered = filtered.filter(todo =>
        todo.text.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    return filtered;
  }, [todos, filter, searchTerm]);

  const handleFilterChange = useCallback((newFilter) => {
    setFilter(newFilter);
  }, []);

  const handleSearchChange = useCallback((e) => {
    setSearchTerm(e.target.value);
  }, []);

  const clearSearch = useCallback(() => {
    setSearchTerm('');
  }, []);

  return (
    <div className="container mx-auto p-4 sm:p-6 lg:p-8 max-w-2xl bg-white shadow-lg rounded-xl my-8">
      <h1 className="text-4xl font-display font-bold text-center text-gray-800 mb-8 flex items-center justify-center gap-3">
        <ListTodo className="w-9 h-9 text-primary-500" />
        My Task List
      </h1>

      <TodoForm addTodo={addTodo} />

      <div className="mt-8">
        <div className="relative mb-6">
          <input
            type="text"
            placeholder="Search tasks..."
            value={searchTerm}
            onChange={handleSearchChange}
            className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-300 focus:border-primary-500 transition duration-200 text-gray-700"
            aria-label="Search tasks"
          />
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
          {searchTerm && (
            <button
              onClick={clearSearch}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700 transition duration-200 p-1 rounded-full"
              aria-label="Clear search"
            >
              <XCircle className="w-5 h-5" />
            </button>
          )}
        </div>

        <div className="flex justify-center gap-3 mb-6 flex-wrap">
          <button
            onClick={() => handleFilterChange('all')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition duration-200 ${
              filter === 'all'
                ? 'bg-primary-500 text-white shadow-md'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
            aria-pressed={filter === 'all'}
          >
            All
          </button>
          <button
            onClick={() => handleFilterChange('active')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition duration-200 ${
              filter === 'active'
                ? 'bg-primary-500 text-white shadow-md'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
            aria-pressed={filter === 'active'}
          >
            Active
          </button>
          <button
            onClick={() => handleFilterChange('completed')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition duration-200 ${
              filter === 'completed'
                ? 'bg-primary-500 text-white shadow-md'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
            aria-pressed={filter === 'completed'}
          >
            Completed
          </button>
        </div>

        {filteredTodos.length === 0 ? (
          <p className="text-center text-gray-500 text-lg mt-10">
            {searchTerm ? "No tasks match your search." : "No tasks yet! Add a new one above."}
          </p>
        ) : (
          <ul className="space-y-4">
            {filteredTodos.map(todo => (
              <TodoItem
                key={todo.id}
                todo={todo}
                toggleComplete={toggleComplete}
                deleteTodo={deleteTodo}
                editTodo={editTodo}
              />
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default TodoList;

