/* Custom styles for scrollbar */
/* For Webkit browsers (Chrome, Safari) */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 10px;
}

::-webkit-scrollbar-thumb {
  background: #cbd5e1; /* slate-300 */
  border-radius: 10px;
}

::-webkit-scrollbar-thumb:hover {
  background: #94a3b8; /* slate-400 */
}

/* For Firefox */
html {
  scrollbar-width: thin;
  scrollbar-color: #cbd5e1 #f1f1f1;
}

/* Base styles for the body and root elements */
body {
  @apply bg-gradient-to-br from-primary-50 to-primary-100 text-gray-800 font-sans antialiased min-h-screen flex items-center justify-center;
}

#root {
  @apply w-full max-w-md mx-auto p-4 sm:p-6 lg:p-8;
}

/* Custom styles for focus-visible */
/* This ensures a consistent focus indicator across interactive elements */
*:focus-visible {
  outline: 2px solid theme('colors.primary.500');
  outline-offset: 2px;
  border-radius: theme('borderRadius.md');
}

/* Custom animation for task completion */
@keyframes strike-through {
  from {
    width: 0;
  }
  to {
    width: 100%;
  }
}

.strike-through-animation {
  position: relative;
}

.strike-through-animation::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 0;
  height: 2px;
  background-color: theme('colors.gray.400');
  animation: strike-through 0.3s ease-out forwards;
}

